.darma-loader-darma-custom-353 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: var(--loader-secondary-color, #fde047);
  --loader-bg: var(--loader-bg, #ffffff);
  display: inline-grid;
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  background: repeating-conic-gradient(from 30deg,var(--loader-color, #ca8a04) 0 60deg,var(--loader-secondary-color, #fde047) 0 120deg);
  animation: darma-loader-darma-custom-353-l10-0 2s linear infinite;
}.darma-loader-darma-custom-353:before,.darma-loader-darma-custom-353:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  background: inherit;
  transform: rotate(0turn) translate(100%,0);
  animation: darma-loader-darma-custom-353-l10-1 3s infinite ease-in-out;
}.darma-loader-darma-custom-353:before {animation-delay: -1.5s;
}@keyframes darma-loader-darma-custom-353-l10-0 {to{rotate: -1turn}}@keyframes darma-loader-darma-custom-353-l10-1 {to{transform: rotate(1turn) translate(100%,0) rotate(1turn)}}

